#include <stdio.h>
long long n,dep,d[70];
void devide(long long k){
	while (k){
		dep++;
		d[dep]=k%2;
		k/=2;
	}
}
long long get(long long i){
	long long m=(1LL<<(dep))-1,c=0,k=i;
	while (k)
	{
		m>>=1;
		c++;
		if (k==m+1)
			break;
		if (k>m+1)
			k-=m+1;
	}
//	printf("%lld",d[c]);
	return c;
}
int main(void){
	long long x,y,i,sum=0;
	scanf("%llu%llu%llu",&n,&x,&y);
	devide(n);
	for (i=x;i<=y;i++)
		sum+=d[get(i)];
	printf("%llu\n",sum);
	return 0;
}

