fn f(n: i64, i: i64) -> i64 {
    if i == 0 {
        return 0;
    }
    let bin_n = format!("{:b}", n);
    let bin_len = bin_n.len();
    let len: i64 = 2_i64.pow(bin_len as u32) - 1;
    if i == len / 2 + 1{
        return n / 2 + n % 2;
    }else if i < len / 2 + 1{
        return f(n / 2, i);
    }
    return n / 2 + n % 2 + f(n / 2, i - (len / 2 + 1));
}
fn main() {
    let s = std::io::stdin();
    let mut sc = Scanner { stdin: s.lock() };
    let n: i64 = sc.read();
    let l: i64 = sc.read();
    let r: i64 = sc.read();
    let res = f(n, r) - f(n, l - 1);
    println!("{}", res);
}

